//! Proto schema merging for combined instruction + event output.

///
/// Merge an instruction proto schema and an event proto schema into a single
/// schema describing `AnchorEventOutput`.
///
/// Both schemas are the `PROTOBUF_SCHEMA` constants generated by
/// `include_vixen_parser!`. They share a common `PublicKey` message and each
/// has an `Instructions` dispatch message as the last entry.
///
/// The merged schema:
/// - Keeps all instruction schema messages, renaming non-identical collisions
///   with a `Struct` suffix (e.g. `TradeEvent` → `TradeEventStruct`) so the
///   event schema's wrapper message keeps the clean name
/// - Includes all event schema messages (except `PublicKey`, which is shared),
///   renaming `Instructions` → `ProgramEvents`. Identical collisions are
///   deduplicated (the instruction copy is kept)
/// - Appends an `AnchorEventOutput` wrapper message with:
///   - `optional Instructions instruction = 1;`
///   - `repeated ProgramEvents program_events = 2;`
///
/// Returns `(combined_schema, wrapper_message_index)` where
/// `wrapper_message_index` is the 0-based position of the `AnchorEventOutput`
/// message in the proto file (matching how `INSTRUCTION_DISPATCH_MESSAGE_INDEX`
/// works in the proc-macro).
///
/// # Example
///
/// ```rust, ignore
/// let (schema, message_index) = merge_proto_schemas(
///     perpetuals::PROTOBUF_SCHEMA,
///     perpetuals_events::PROTOBUF_SCHEMA,
/// );
/// ```
///
#[must_use]
pub fn merge_proto_schemas(ix_schema: &str, event_schema: &str) -> (String, i32) {
    let ix_messages = parse_message_blocks(ix_schema);
    let event_messages = parse_message_blocks(event_schema);

    // Build lookups for collision detection.
    let ix_map: std::collections::HashMap<&str, &str> = ix_messages
        .iter()
        .map(|m| (m.name.as_str(), m.raw.as_str()))
        .collect();

    let event_map: std::collections::HashMap<&str, &str> = event_messages
        .iter()
        .map(|m| (m.name.as_str(), m.raw.as_str()))
        .collect();

    // Determine which instruction messages need a `Struct` suffix because they
    // collide with a non-identical event message of the same name.
    // The event schema's wrapper message keeps the clean name.
    let mut ix_rename_map: std::collections::HashMap<&str, String> =
        std::collections::HashMap::new();

    for msg in &ix_messages {
        if msg.name == "PublicKey" || msg.name == "Instructions" {
            continue;
        }

        if let Some(ev_raw) = event_map.get(msg.name.as_str())
            && *ev_raw != msg.raw
        {
            ix_rename_map.insert(msg.name.as_str(), format!("{}Struct", msg.name));
        }
    }

    // Second pass: detect "indirect collisions" — ix messages with identical
    // raw bodies as their event counterpart, but whose bodies reference
    // renamed types. After renaming, the ix body will diverge, so the ix
    // wrapper must also be renamed to avoid a duplicate definition.
    let mut changed = true;

    while changed {
        changed = false;

        for msg in &ix_messages {
            if msg.name == "PublicKey"
                || msg.name == "Instructions"
                || ix_rename_map.contains_key(msg.name.as_str())
            {
                continue;
            }

            if event_map.contains_key(msg.name.as_str())
                && references_renamed_type(&msg.raw, &ix_rename_map)
            {
                ix_rename_map.insert(msg.name.as_str(), format!("{}Struct", msg.name));
                changed = true;
            }
        }
    }

    let mut out = String::with_capacity(ix_schema.len() + event_schema.len() + 256);

    out.push_str("syntax = \"proto3\";\n\n");

    // Emit instruction schema messages, renaming non-identical collisions.
    for msg in &ix_messages {
        let block = apply_renames(&msg.raw, &ix_rename_map);

        out.push_str(&block);
        out.push_str("\n\n");
    }

    // Emit event schema messages:
    //  - Skip `PublicKey` (shared, already emitted from instruction schema)
    //  - Skip messages identical to ones in the instruction schema (dedup)
    //  - Rename `Instructions` → `ProgramEvents`
    let mut emitted_count = 0;

    for msg in &event_messages {
        if msg.name == "PublicKey" {
            continue;
        }

        // Deduplicate: identical definitions already emitted from the
        // instruction schema — but only when the ix-side block was NOT
        // altered by renames (otherwise the event version is needed as-is).
        if msg.name != "Instructions"
            && !ix_rename_map.contains_key(msg.name.as_str())
            && let Some(ix_raw) = ix_map.get(msg.name.as_str())
            && !references_renamed_type(ix_raw, &ix_rename_map)
        {
            continue;
        }

        let mut block = msg.raw.clone();

        if msg.name == "Instructions" {
            block = block.replacen("message Instructions", "message ProgramEvents", 1);
        }

        out.push_str(&block);
        out.push_str("\n\n");

        emitted_count += 1;
    }

    // Append the wrapper message.
    out.push_str(
        "message AnchorEventOutput {\n\x20 optional Instructions instruction = 1;\n\x20 repeated \
         ProgramEvents program_events = 2;\n}\n",
    );

    // message_index is the 0-based position of the target message in the
    // proto file (matching INSTRUCTION_DISPATCH_MESSAGE_INDEX from proc-macro).
    let total = ix_messages.len() + emitted_count + 1; // +1 for AnchorEventOutput

    #[allow(clippy::cast_possible_truncation, clippy::cast_possible_wrap)]
    let message_index = (total - 1) as i32;

    (out, message_index)
}

///
/// Replace proto type names as whole words in a block of text.
///
/// Sorts rename pairs longest-first so `ExpireToken` is matched before `Expire`,
/// then replaces only at word boundaries (preceded/followed by a non-alphanumeric
/// character or start/end of string).
///
fn apply_renames(block: &str, renames: &std::collections::HashMap<&str, String>) -> String {
    if renames.is_empty() {
        return block.to_string();
    }

    // Sort longest-first to prevent shorter keys from matching as prefixes.
    let mut pairs: Vec<_> = renames.iter().collect();

    pairs.sort_by(|a, b| b.0.len().cmp(&a.0.len()));

    let mut result = block.to_string();

    for (old, new) in pairs {
        let mut out = String::with_capacity(result.len());
        let mut remaining = result.as_str();

        while let Some(pos) = remaining.find(old) {
            let before = if pos == 0 {
                None
            } else {
                remaining.as_bytes().get(pos - 1).copied()
            };

            let after = remaining.as_bytes().get(pos + old.len()).copied();

            let is_word_boundary =
                |c: Option<u8>| c.is_none_or(|b| !b.is_ascii_alphanumeric() && b != b'_');

            out.push_str(&remaining[..pos]);

            if is_word_boundary(before) && is_word_boundary(after) {
                out.push_str(new);
            } else {
                out.push_str(old);
            }

            remaining = &remaining[pos + old.len()..];
        }

        out.push_str(remaining);

        result = out;
    }

    result
}

/// Check whether a proto block body references any of the renamed type names
/// (whole-word match only).
fn references_renamed_type(raw: &str, renames: &std::collections::HashMap<&str, String>) -> bool {
    for old in renames.keys() {
        let mut remaining = raw.as_bytes();

        let old_bytes = old.as_bytes();

        while let Some(pos) = remaining
            .windows(old_bytes.len())
            .position(|w| w == old_bytes)
        {
            let before = if pos == 0 {
                None
            } else {
                Some(remaining[pos - 1])
            };

            let after = remaining.get(pos + old_bytes.len()).copied();

            let is_word_boundary =
                |c: Option<u8>| c.is_none_or(|b| !b.is_ascii_alphanumeric() && b != b'_');

            if is_word_boundary(before) && is_word_boundary(after) {
                return true;
            }

            remaining = &remaining[pos + old_bytes.len()..];
        }
    }

    false
}

/// A parsed proto message block: its name and the raw text (including the
/// `message Name { ... }` wrapper).
struct MessageBlock {
    name: String,
    raw: String,
}

/// Parse a proto schema string into a list of top-level message blocks.
///
/// Handles nested braces (e.g. `oneof { ... }` inside a message).
fn parse_message_blocks(schema: &str) -> Vec<MessageBlock> {
    let mut blocks = Vec::new();
    let mut lines = schema.lines().peekable();

    while let Some(line) = lines.next() {
        let trimmed = line.trim();

        // Match `message FooBar {`
        if !trimmed.starts_with("message ") {
            continue;
        }

        let Some(name) = trimmed
            .strip_prefix("message ")
            .and_then(|rest| rest.split_whitespace().next())
        else {
            continue;
        };

        // Accumulate the full block including nested braces.
        let mut raw = String::new();

        raw.push_str(line);
        raw.push('\n');

        let mut depth = trimmed.matches('{').count();

        depth -= trimmed.matches('}').count();

        while depth > 0 {
            let Some(inner) = lines.next() else {
                break;
            };

            raw.push_str(inner);
            raw.push('\n');

            depth += inner.matches('{').count();
            depth -= inner.matches('}').count();
        }

        // Trim trailing newline for cleaner output.
        let raw = raw.trim_end_matches('\n').to_string();

        blocks.push(MessageBlock {
            name: name.to_string(),
            raw,
        });
    }

    blocks
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn merge_simple_schemas() {
        let ix_schema = "\
syntax = \"proto3\";

package my_program;

message PublicKey {
  bytes value = 1;
}

message SwapAccounts {
  PublicKey user = 1;
}

message SwapArgs {
  uint64 amount = 1;
}

message Swap {
  SwapAccounts accounts = 1;
  SwapArgs args = 2;
}

message Instructions {
  oneof instruction {
    Swap swap = 1;
  }
}
";

        let event_schema = "\
syntax = \"proto3\";

package my_program_events;

message PublicKey {
  bytes value = 1;
}

message TradeEventAccounts {
  repeated PublicKey remaining_accounts = 1;
}

message TradeEventArgs {
  uint64 price = 1;
}

message TradeEvent {
  TradeEventAccounts accounts = 1;
  TradeEventArgs args = 2;
}

message Instructions {
  oneof instruction {
    TradeEvent trade_event = 1;
  }
}
";

        let (combined, message_index) = merge_proto_schemas(ix_schema, event_schema);

        // Should contain instruction types
        assert!(combined.contains("message SwapAccounts"));
        assert!(combined.contains("message Instructions {"));

        // Should contain event types
        assert!(combined.contains("message TradeEventAccounts"));
        assert!(combined.contains("message TradeEvent {"));

        // Instructions renamed to ProgramEvents
        assert!(combined.contains("message ProgramEvents {"));

        // PublicKey appears exactly once
        assert_eq!(
            combined.matches("message PublicKey {").count(),
            1,
            "PublicKey should be deduplicated"
        );

        // Wrapper message
        assert!(combined.contains("message AnchorEventOutput {"));
        assert!(combined.contains("optional Instructions instruction = 1;"));
        assert!(combined.contains("repeated ProgramEvents program_events = 2;"));

        // Message index: 5 ix + 4 event (minus PublicKey) + 1 wrapper = 10, index = 9
        assert_eq!(message_index, 9);
    }

    #[test]
    fn merge_dedup_identical_collision() {
        let ix_schema = "\
syntax = \"proto3\";

message PublicKey {
  bytes value = 1;
}

message SharedType {
  uint64 amount = 1;
}

message Instructions {
  oneof instruction {
    SharedType shared_type = 1;
  }
}
";

        let event_schema = "\
syntax = \"proto3\";

message PublicKey {
  bytes value = 1;
}

message SharedType {
  uint64 amount = 1;
}

message Instructions {
  oneof instruction {
    SharedType shared_type = 1;
  }
}
";

        let (combined, _) = merge_proto_schemas(ix_schema, event_schema);

        // Identical `SharedType` should appear only once (deduplicated).
        assert_eq!(
            combined.matches("message SharedType {").count(),
            1,
            "Identical collision should be deduplicated"
        );
    }

    #[test]
    fn merge_rename_ix_side_non_identical_collision() {
        let ix_schema = "\
syntax = \"proto3\";

message PublicKey {
  bytes value = 1;
}

message Overlap {
  uint64 amount = 1;
}

message Instructions {
  oneof instruction {
    Overlap overlap = 1;
  }
}
";

        let event_schema = "\
syntax = \"proto3\";

message PublicKey {
  bytes value = 1;
}

message Overlap {
  string name = 1;
  uint64 price = 2;
}

message Instructions {
  oneof instruction {
    Overlap overlap = 1;
  }
}
";

        let (combined, message_index) = merge_proto_schemas(ix_schema, event_schema);

        // Instruction-side `Overlap` renamed to `OverlapStruct`.
        assert!(
            combined.contains("message OverlapStruct {"),
            "Instruction Overlap should be renamed to OverlapStruct"
        );

        // References inside instruction dispatch updated.
        assert!(
            combined.contains("OverlapStruct overlap"),
            "Instruction dispatch should reference OverlapStruct"
        );

        // Event-side `Overlap` keeps the clean name.
        assert!(
            combined.contains("message Overlap {"),
            "Event Overlap should keep the clean name"
        );

        // Event dispatch references unchanged.
        assert!(
            combined.contains("    Overlap overlap"),
            "Event dispatch (ProgramEvents) should reference Overlap"
        );

        // 3 ix + 2 event (Overlap + ProgramEvents) + 1 wrapper = 6, index = 5
        assert_eq!(message_index, 5);
    }
}
